mapper.select:
SELECT COUNT(*) AS total, SUM(CASE WHEN up.gender='남자' THEN 1 ELSE 0 END) AS male, SUM(CASE WHEN up.gender='여자' THEN 1 ELSE 0 END) AS female FROM attendance a JOIN users u ON a.user_id = u.user_id LEFT JOIN user_profiles up ON u.user_id = up.user_id
AND a.attend_date BETWEEN DATE_SUB(#{date}, INTERVAL WEEKDAY(#{date}) DAY) AND DATE_ADD(DATE_SUB(#{date}, INTERVAL WEEKDAY(#{date}) DAY), INTERVAL 6 DAY)
AND DATE_FORMAT(a.attend_date, '%Y-%m') = DATE_FORMAT(#{date}, '%Y-%m')
AND a.attend_date=#{date}
AND a.type=#{type}
